    container.innerHTML = `
        <div class="shield-bar" style="width: ${shieldPercentage}%;"></div>
        <div class="health-bar" style="width: ${healthPercentage}%;"></div>
        <span class="bar-text">${currentHp} / ${maxHp} ${shield > 0 ? `<span style="color: #93c5fd;">(+${shield})</span>` : ''}</span>
